var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크윽!!","JPN":"くっ！！","ENG":"Hngh!","TWN":"唔！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 물러서세요.","JPN":"ミナさん、下がってください。","ENG":"Mina, stay back.","TWN":"米娜，你退下！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괘, 괜찮아. 이 정도쯤…….","JPN":"だ、大丈夫。これくらい……","ENG":"I-I’m okay, I can handle it...","TWN":"我…我沒事，才這點程度……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 말을 하기엔 피를 너무 흘린 것 같은데요?","JPN":"そう言うには血を流しすぎですよ。","ENG":"But you’re bleeding heavily.","TWN":"說這種話之前，你要先看看你流了多少血嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무리하지 말고 제 뒤로 물러서세요.","JPN":"無理しないで、僕の後ろに下がっていてください。","ENG":"I’m telling you, stay back.","TWN":"不要逞強，快到我後面來！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만……","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"괜찮습니다. 샬롯 양도 더 싸울 생각은 없어 보이니까요.","JPN":"大丈夫です。シャーロットさんもこれ以上戦うつもりはなさそうですから。","ENG":"It’s okay. I don’t think Carlota wants to fight anymore either.","TWN":"放心，我看夏洛特應該也沒有要再打下去的意思。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>마검 사파이어 프리즌 – 클리포트 인자 추출 완료.</color>","JPN":"<color=#ffd34c>魔剣サファイアプリズン　-　クリフォト・ファクター抽出完了。</color>","ENG":"<color=#ffd34c>Sapphire Prison, the Evil Sword - Qliphoth Factor extraction complete.</color>","TWN":"<color=#ffd34c>魔劍 藍寶稜鏡–逆卡巴拉因子取出完畢。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>타입 – 펜릴 확인. 결정화 개시.</color>","JPN":"<color=#ffd34c>タイプ-フェンリルを確認。結晶化開始。</color>","ENG":"<color=#ffd34c>Fenrir Type confirmed. Crystallization initiated.</color>","TWN":"<color=#ffd34c>Type：芬里爾確認。開始結晶化。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"임무…… 완료.","JPN":"任務……完了。","ENG":"Mission... accomplished.","TWN":"任務……完成。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건……?","JPN":"あれは……？","ENG":"What’s that?","TWN":"那個是……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양의 피……. 아니, 정확히는 클리포트 인자를 추출해 결정으로 만든 모양이군요.","JPN":"ミナさんの血……いえ、正確にはクリフォト・ファクターを抽出して\\n結晶化したようですね。","ENG":"It’s your blood... or rather, a crystallized version of your extracted Qliphoth Factor.","TWN":"是用米娜的血……不，正確來說，應該是將逆卡巴拉因子取出後，製造而成的結晶。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"꼭 보석 같아 보이는데, 그게 당신의 진짜 임무였나 보죠?","JPN":"まるで宝石のようですね。\\nそれがあなたの本当の任務だったんですか？","ENG":"It looks like a jewel. So this was your real mission?","TWN":"看起來很像寶石，這就是你真正的任務吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……그렇다.","JPN":"……そうだ。","ENG":"Yes.","TWN":"……沒錯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"하지만 임무가 끝나면…… 다음 임무가 시작될 뿐.","JPN":"だが、任務が終われば……次の任務が始まるのみ。","ENG":"But when one mission ends, another mission starts.","TWN":"不過任務結束……也不過是表示下一個任務的開始而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가문이 명예를 회복할 때까지 휴식은 주어지지 않는다.","JPN":"一族の名誉を回復するまで、休息は許されない。","ENG":"I will never be able to rest until I clear my family's name.","TWN":"在家族恢復榮耀前，我是不能休息的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네 가문에 대체 무슨 일이 있었는지는 모르겠어.","JPN":"あなたの一族に何があったのかはわからない。","ENG":"I don’t know what happened to your family.","TWN":"我是不清楚你的家族發生什麼事，"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만……. 이런 짓을 한다고 정말 그 명예가 회복될 수 있는 거야?","JPN":"でも……こんなことをしたからって、本当にその名誉は取り戻せるの？","ENG":"But... do you really believe that doing something like this will actually help?","TWN":"但是……你真的認為做這種事，就能恢復家族的榮耀嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 너처럼 기사도, 귀족도 아냐.","JPN":"私はあなたのように、騎士でも貴族でもない。","ENG":"I’m not a knight nor a noblewoman like you.","TWN":"我跟你不一樣，既不是騎士，也不是貴族。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 명예라는 건 명예로운 일을 해야 얻는 거 아냐?","JPN":"でも、名誉とは人に誇れることをして得られるものでしょ？","ENG":"If you really want to regain your honor, you have to do something honorable, don’t you think?","TWN":"但我知道，要做榮耀的事才能有榮耀，不是嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너와 네 동료들이 하는 일들은 전혀……!","JPN":"あなたとあなたの仲間がしていることは全然……！","ENG":"But what you and your colleagues are doing is not honorable at all!","TWN":"你和你的夥伴，你們的所作所為完全……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"넌 자유로운 자로군. 예전에도, 지금도.","JPN":"君は自由なんだな。昔も、今も。","ENG":"You’re a free spirit. In the past, and now.","TWN":"你是一個自由的人，無論是以前或現在。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇기에 나는 너처럼 살아갈 수 없다.","JPN":"だから私は君のようには生きていけない。","ENG":"I will never be able to live like you.","TWN":"但我無法像你一樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"나는 태어날 때부터 가문과 의무에 구속된 자.","JPN":"私は生まれながらにして一族と義務に拘束された者。","ENG":"I was bound to my family and my duty since I was born.","TWN":"我從一出生就受制於家族的義務。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아니. 가문과 의무를 위해 태어난 자다.","JPN":"いや、一族と義務のために生まれた存在だ。","ENG":"Or rather, I was born for my family and my duty.","TWN":"不，應該是說我就是為承擔家族義務而生的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"신념이 꺾이고 아무리 비참한 신세가 되더라도……. 가문이 내게 건 기대를 배신할 수는 없어.","JPN":"信念が折れてどんなに惨めな身になったとしても……\\n一族が私にかけた期待を裏切るわけにはいかないのだ。","ENG":"No matter how degrading and miserable I become... I will never betray my family.","TWN":"就算違背信念，變得有多狼狽……我都不能辜負家族對我的期待。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 말도 안 되는 소릴……!","JPN":"そんなデタラメなこと……！","ENG":"That’s ridiculous!","TWN":"在胡說八道什麼……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이해해 주지 않아도 좋다. 이젠 헤어질 시간이니까.","JPN":"理解してくれなくても構わない。そろそろお別れの時間だ。","ENG":"I don’t expect you to understand. It’s time for me to go.","TWN":"你不能理解也無所謂，反正我要離開了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"짧은 만남이었지만……. 다시 볼 수 있어서……","JPN":"短い間だったが……また会えて……","ENG":"It was only for a short time... but I was glad to see you again...","TWN":"雖然這次相處的時間很短暫……但我們會再見的……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>라이트닝──! 익스큐션──!!</color>","JPN":"<color=#ffd34c>ライトニング──！　エクスキューージョン！！</color>","ENG":"<color=#ffd34c>Lightning ──! Execution ──!</color>","TWN":"<color=#ffd34c>雷光──！處刑──！！</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};